-- {"operators": "INNER_JOIN,AGGREGATE,HAVING,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER,ORDER_LINE", "ducklake": true}
WITH order_totals AS (SELECT ol.OL_W_ID, ol.OL_D_ID, ol.OL_O_ID, SUM(ol.OL_AMOUNT) AS order_total FROM dl.ORDER_LINE ol GROUP BY ol.OL_W_ID, ol.OL_D_ID, ol.OL_O_ID) SELECT c.C_W_ID, c.C_D_ID, c.C_ID, c.C_LAST, COUNT(o.O_ID) AS n_orders, SUM(ot.order_total) AS grand_total FROM dl.CUSTOMER c JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID JOIN order_totals ot ON o.O_W_ID = ot.OL_W_ID AND o.O_D_ID = ot.OL_D_ID AND o.O_ID = ot.OL_O_ID GROUP BY c.C_W_ID, c.C_D_ID, c.C_ID, c.C_LAST HAVING SUM(ot.order_total) > 50;
